import{$,on,initI18n,getLang,setLang,t,applyStaticI18n,applyImage,}from"./utils.js";import*as menu from"./menu.js";import*as story from"./story.js";import*as swipe from"./swipe.js";import*as animations from"./animations.js";import*as parallax from"./parallax.js";import*as loader from"./loader.js";async function boot(){const stringsPromise=fetch("data/i18n.json",{cache:"no-cache"}).then((r)=>r.json());const dataPromise=menu.loadData();const storyPromise=story.loadStory();const loaderDone=loader.run(dataPromise,storyPromise);let strings={en:{},ar:{}};try{strings=await stringsPromise;}catch(err){console.warn("[kristo] i18n load failed",err);}
initI18n(strings);applyStaticI18n();updateLangButton();$("#lang-toggle").addEventListener("click",onLangToggle);try{await dataPromise;}catch(err){console.error("[kristo] menu load failed",err);menu.renderError();await loaderDone;return;}
await storyPromise;menu.render();menu.initSheet();injectMenuSchema();swipe.init();swipe.initNavAutoHide();animations.init();animations.bindImages(applyImage);idle(()=>{animations.bindDishes();parallax.init();});await loaderDone;animations.heroEntrance();if("serviceWorker"in navigator&&location.protocol!=="file:"){navigator.serviceWorker.register("sw.js").catch((err)=>{console.warn("[kristo] sw registration failed",err);});}}
function injectMenuSchema(){const data=menu.getData();if(!data)return;const sections=(data.categories||[]).map((cat)=>({"@type":"MenuSection",name:cat.label?.ar||cat.id,hasMenuItem:data.dishes.filter((d)=>d.category===cat.id).map((d)=>{const item={"@type":"MenuItem",name:d.name?.ar||d.id,description:d.description?.ar||""};if(d.price!=null){item.offers={"@type":"Offer",price:String(d.price),priceCurrency:"SAR"};}
return item;}),}));const schema={"@context":"https://schema.org","@type":"Menu",name:"منيو كريستو",inLanguage:"ar",hasMenuSection:sections,};const el=document.createElement("script");el.type="application/ld+json";el.textContent=JSON.stringify(schema);document.head.append(el);}
const idle=(fn)=>("requestIdleCallback"in window?requestIdleCallback(fn,{timeout:400}):setTimeout(fn,120));function onLangToggle(){const next=getLang()==="ar"?"en":"ar";setLang(next);applyStaticI18n();updateLangButton();if(!menu.getData()){menu.renderError();return;}
const keepIndex=swipe.getActiveIndex();menu.render();swipe.rebind(keepIndex);animations.bindDishes();animations.bindImages(applyImage);parallax.bind();if(window.gsap)gsap.set(".hero__cats > *, .hero .swipe-hint",{opacity:1,y:0,scale:1});}
function updateLangButton(){const btn=$("#lang-toggle");const ar=getLang()==="ar";btn.textContent=ar?"EN":"ع";btn.setAttribute("aria-label",ar?"Switch to English":"التبديل إلى العربية");}
if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",boot);}else{boot();}